5: use std::path::Path;
6: use std::process::Command;
7: use std::{env, fs};
8: 
9: fn main() {
10:     if cfg!(feature = "media-gstreamer") {
11:         println!("cargo:rerun-if-changed=../../python/servo/gstreamer.py");
12: 
13:         let output = find_python()
14:             .arg("../../python/servo/gstreamer.py")
15:             .arg(std::env::var_os("TARGET").unwrap())
16:             .output()
17:             .unwrap();
18:         if !output.status.success() {
19:             eprintln!("{}", String::from_utf8_lossy(&output.stdout));
20:             eprintln!("{}", String::from_utf8_lossy(&output.stderr));
21:             std::process::exit(1)
22:         }
23:         let path = Path::new(&env::var_os("OUT_DIR").unwrap()).join("gstreamer_plugins.rs");
24:         fs::write(path, output.stdout).unwrap();
25:     }
26: }
27: 
28: fn try_python_command(mut command: Command) -> Result<Command, String> {
29:     let command_result = command.output();
30: 
31:     if let Ok(output) = command_result {
32:         return if output.status.success() {
33:             Ok(command)
34:         } else {
35:             Err(format!(
36:                 "`{command:?}` failed with {}",
37:                 String::from_utf8_lossy(&output.stderr)
38:             ))
39:         };
40:     }
