44: /// Tries to find a suitable python, which in Servo is always `uv run python`.
45: ///
46: /// To be accommodating to different environments, which may manage python differently, we fallback
47: /// to `python3` and `python` in that order.
48: ///
49: /// Note: This function should be kept in sync with the version in `components/script_bindings/build.rs`
50: fn find_python() -> Command {
51:     let mut command = Command::new("uv");
52:     command.args(["run", "--frozen", "python"]);
53: 
54:     let command_result = try_python_command(command).inspect_err(|e| println!("cargo:warning={e}"));
55:     if let Ok(command) = command_result {
56:         return command;
57:     }
58: 
59:     println!(
60:         "cargo:warning=`uv` not found - Falling back to the default python! \
61:         If the build fails, please install uv and make sure it is in your PATH or make sure \
62:         to provision a python environment >= python 3.11."
63:     );
64: 
65:     let python3 = Command::new("python3");
66:     let python3_result = try_python_command(python3);
67:     if let Ok(command) = python3_result {
68:         return command;
69:     }
70: 
71:     let python = Command::new("python");
72:     let python_result = try_python_command(python);
73:     if let Ok(command) = python_result {
74:         return command;
75:     }
76: 
77:     // We first try `python` before printing an error for `python3`, since python3 is often missing
78:     // provided via python on Windows (but not necessarily on linux).
79:     println!("cargo:warning={}", python3_result.unwrap_err());
80:     println!("cargo:warning={}", python_result.unwrap_err());
81: 
82:     panic!("No suitable python found! Tried: `uv run python`, `python3`, `python`.");
83: }
